        cur.execute("\n        CREATE TABLE IF NOT EXISTS asistidos(\n          id INTEGER PRIMARY KEY AUTOINCREMENT,\n          nombre TEXT NOT NULL,\n          barrio TEXT,\n          direccion TEXT,\n          referencia TEXT,\n          telefono TEXT,\n          lat REAL,\n          lng REAL,\n          estado TEXT NOT NULL DEFAULT 'NO_REALIZADA',\n          creado_en TEXT DEFAULT (date('now'))\n        )\n        ")
