        ensure_cols(con, 'sst_ergonomia', [('altura_monitor', 'TEXT'), ('espacio_piernas', 'TEXT'), ('ajuste_altura', 'TEXT'), ('horas_pc', 'INTEGER'), ('uso_notebook', 'TEXT'), ('fecha_relevamiento', 'TEXT'), ('evaluador', 'TEXT'), ('fecha_nacimiento', 'TEXT'), ('puntuacion_edad', 'INTEGER'), ('estado_flujo', 'TEXT'), ('fecha_implementacion', 'TEXT'), ('responsable', 'TEXT'), ('evidencia_url', 'TEXT'), ('fecha_verificacion', 'TEXT'), ('verificado', 'INTEGER'), ('audit_alertas', 'TEXT'), ('intervencion_realizada', 'TEXT'), ('fecha_cierre', 'TEXT'), ('fecha_recordatorio', 'TEXT'), ('pro_condicion_0_100', 'REAL'), ('pro_expo_0_100', 'REAL'), ('pro_vulner_0_100', 'REAL'), ('pro_score_final', 'REAL'), ('pro_condicion_riesgo', 'TEXT'), ('pro_motivos', 'TEXT'), ('salud_evaluador', 'TEXT'), ('salud_fecha', 'TEXT')])
